class Foo {
    private static int _counter = 0; // flagged if incremented

    public void Increment() {
        _counter++;
    }
}


class Server {
    private Dictionary<string, int> _conns;
    private Dictionary<string, int> _stats;

    public void Accept(string addr) { _conns[addr] = 1; }
    public void Record(string k)    { _stats[k]++; }
    // Two disjoint clusters → LCOM4 = 2 → violation
}
